fn determine_backend(req: &Request) -> &'static str {
    let path = req.get_path();
    let method = req.get_method();

    if path.starts_with("/api/") || path.starts_with("/v1/") || path.starts_with("/v2/") {
        BACKEND_API
    } else if path.starts_with("/static/")
        || path.starts_with("/assets/")
        || path.starts_with("/images/")
        || path.starts_with("/css/")
        || path.starts_with("/js/")
    {
        BACKEND_STATIC
    } else if path.starts_with("/auth/")
        || path.starts_with("/login")
        || path.starts_with("/logout")
        || path.starts_with("/oauth/")
    {
        BACKEND_AUTH
    } else {
        BACKEND_DEFAULT
    }
}

fn add_request_headers(req: &mut Request, backend_config: &BackendConfig) {
    req.set_header("X-Forwarded-Proto", "https");
    req.set_header("X-Backend-Name", backend_config.name);
    req.set_header(header::HOST, backend_config.host);

    if !req.contains_header("X-Request-Id") {
        let request_id = fastly::handle::client_request_id();
        req.set_header("X-Request-Id", request_id.to_string());
    }
}

fn handle_cors_preflight(req: &Request) -> Option<Response> {
    if req.get_method() == Method::OPTIONS {
        let origin = req
            .get_header_str("Origin")
            .unwrap_or("*")
            .to_string();

        let response = Response::from_status(StatusCode::NO_CONTENT)
            .with_header("Access-Control-Allow-Origin", origin)
            .with_header(
                "Access-Control-Allow-Methods",
                "GET, POST, PUT, DELETE, PATCH, OPTIONS",
            )
            .with_header(
                "Access-Control-Allow-Headers",
                "Content-Type, Authorization, X-Request-Id",
            )
            .with_header("Access-Control-Max-Age", "86400")
            .with_header("Content-Length", "0");

        return Some(response);
    }
    None
}

fn add_cors_headers(resp: &mut Response, origin: Option<&str>) {
    let origin_value = origin.unwrap_or("*");
    resp.set_header("Access-Control-Allow-Origin", origin_value);
    resp.set_header(
        "Access-Control-Allow-Methods",
        "GET, POST, PUT, DELETE, PATCH, OPTIONS",
    );
    resp.set_header(
        "Access-Control-Allow-Headers",
        "Content-Type, Authorization, X-Request-Id",
    );
}

fn add_security_headers(resp: &mut Response) {
    resp.set_header("X-Content-Type-Options", "nosniff");
    resp.set_header("X-Frame-Options", "DENY");
    resp.set_header("X-XSS-Protection", "1; mode=block");
    resp.set_header(
        "Strict-Transport-Security",
        "max-age=31536000; includeSubDomains",
    );
    resp.set_header("Referrer-Policy", "strict-origin-when-cross-origin");
}

fn handle_health_check() -> Response {
    Response::from_status(StatusCode::OK)
        .with_content_type(mime::APPLICATION_JSON)
        .with_body(r#"{"status":"healthy","service":"edge-router"}"#)
}

fn create_error_response(status: StatusCode, message: &str) -> Response {
    let body = format!(
        r#"{{"error":true,"status":{},"message":"{}"}}"#,
        status.as_u16(),
        message
    );

    Response::from_status(status)
        .with_content_type(mime::APPLICATION_JSON)
        .with_body(body)
}

fn send_to_backend(mut req: Request, backend_name: &str, config: &BackendConfig) -> Result<Response, Error> {
    add_request_headers(&mut req, config);

    let backend = Backend::from_name(backend_name)?;

    match req.send(backend) {
        Ok(mut resp) => {
            let origin = resp
                .get_header_str("X-Original-Origin")
                .map(|s| s.to_string());
            add_cors_headers(&mut resp, origin.as_deref());
            add_security_headers(&mut resp);
            resp.set_header("X-Served-By", "fastly-edge-router");
            resp.set_header("X-Backend", backend_name);
            Ok(resp)
        }
        Err(e) => {
            eprintln!("Backend request failed for {}: {:?}", backend_name, e);
            Ok(create_error_response(
                StatusCode::BAD_GATEWAY,
                &format!("Backend {} is unavailable", backend_name),
            ))
        }
    }
}

#[fastly::main]
fn main(req: Request) -> Result<Response, Error> {
    // Handle health check endpoint
    if req.get_path() == "/health" || req.get_path() == "/__health" {
        return Ok(handle_health_check());
    }

    // Handle CORS preflight requests
    if let Some(preflight_response) = handle_cors_preflight(&req) {
        return Ok(preflight_response);
    }

    // Block disallowed methods
    match req.get_method() {
        &Method::GET
        | &Method::POST
        | &Method::PUT
        | &Method::DELETE
        | &Method::PATCH
        | &Method::HEAD => {}
        _ => {
            return Ok(create_error_response(
                StatusCode::METHOD_NOT_ALLOWED,
                "Method not allowed",
            ));
        }
    }

    // Load backend configurations
    let configs = get_backend_configs();
    let config_map: HashMap<&str, &BackendConfig> = configs.iter().map(|c| (c.name, c)).collect();

    // Determine which backend to route to
    let backend_name = determine_backend(&req);

    // Get the backend configuration
    let backend_config = match config_map.get(backend_name) {
        Some(config) => config,
        None => {
            return Ok(create_error_response(
                StatusCode::INTERNAL_SERVER_ERROR,
                "Backend configuration not found",
            ));
        }
    };

    println!(
        "Routing {} {} to backend {} ({}:{})",
        req.get_method(),
        req.get_path(),
        backend_name,
        backend_config.host,
        backend_config.port
    );

    // Send request to the determined backend
    send_to_backend(req, backend_name, backend_config)
}

